   private int insertForm(SesEmailData sesEmailData,
                          NUIForm form, APIQuery aq) {
      SimpleDateFormat sdf = new SimpleDateFormat("yyyy/MM/dd HH:mm:ss");

      CellInfo subjectField = form.getFieldByAttribute("email_subject", null);
      CellInfo contentField = form.getFieldByAttribute("email_content", null);
      CellInfo createDateField = form.getFieldByAttribute("email_createDate", null);
      CellInfo lastUpdateDateField = form.getFieldByAttribute("email_updateDate", null);
      CellInfo lastUpdateEmailField = form.getFieldByAttribute("email_updateEmail", null);
      CellInfo fromEmailField = form.getFieldByAttribute("email_fromAddress", null);
      CellInfo fromPersonalField = form.getFieldByAttribute("email_fromPersonal", null);
      CellInfo toField = form.getFieldByAttribute("email_toAddress", null);//[BugId:08587]
      CellInfo toPersonalField = form.getFieldByAttribute("email_toPersonal", null);//[BugId:08624]
      CellInfo ccField = form.getFieldByAttribute("email_ccAddress", null);//[BugId:08587]
      CellInfo ccPersonalField = form.getFieldByAttribute("email_ccPersonal", null);//[BugId:08587]
      CellInfo needActionField = form.getFieldByAttribute("email_needAction", null);
      CellInfo debugField = form.getFieldByAttribute("email_debug", null);

      String fromAddress = getFromAddress(sesEmailData.getFrom());
      String fromPersonal = getFromPersonal(sesEmailData.getFrom());

      APIEntry ae = aq.insertAPIEntry();
      if (subjectField != null) ae.setFieldValue(subjectField.getDomainId(), sesEmailData.getSubject());//subject

      if (contentField != null) ae.setFieldValue(contentField.getDomainId(), Encoder.removeHTML(sesEmailData.getContentPlain()));

      if (createDateField != null)
         ae.setFieldValue(createDateField.getDomainId(), sdf.format(new Date()));//create date

      if (lastUpdateDateField != null)
         ae.setFieldValue(lastUpdateDateField.getDomainId(), sdf.format(new Date()));//last update

      if (lastUpdateEmailField != null)
         ae.setFieldValue(lastUpdateEmailField.getDomainId(), fromAddress);//last update user

      if (fromEmailField != null) ae.setFieldValue(fromEmailField.getDomainId(), fromAddress);//from email

      if (fromPersonalField != null) ae.setFieldValue(fromPersonalField.getDomainId(), fromPersonal);//from personal

      if (toField != null || toPersonalField != null) {
         //[BugId:08624, 14556]
         String toEmail = sesEmailData.getAddressJoinByType(SesEmailData.Type.TO);
         String toPersonal = sesEmailData.getPersonalJoinByType(SesEmailData.Type.TO);

         if (toField != null) ae.setFieldValue(toField.getDomainId(), toEmail);//to list [BugId:08587]
         if (toPersonalField != null) ae.setFieldValue(toPersonalField.getDomainId(), toPersonal);
      }

      if (ccField != null || ccPersonalField != null) {
         //[BugId:08624, 14556]
         String ccEmail = sesEmailData.getAddressJoinByType(SesEmailData.Type.CC);
         String ccPersonal = sesEmailData.getPersonalJoinByType(SesEmailData.Type.CC);

         if (ccField != null) ae.setFieldValue(ccField.getDomainId(), ccEmail);//to list [BugId:08587]
         if (ccPersonalField != null) ae.setFieldValue(ccPersonalField.getDomainId(), ccPersonal);
      }

      boolean autoNoAction = getAutoNoActionByFromAddress(getFromAddress(sesEmailData.getFrom()));
      if (needActionField != null)
         ae.setFieldValue(needActionField.getDomainId(), autoNoAction ? "N" : "Y");//need action = y
      //if(debugField!=null) ae.setFieldValue(debugField.getDomainId(),contentIdMapping.toString(2));

      ae.loadAllDefaultValues(new UserSuper(fromAddress));
      ae.recalculateAllFormulas();//[BugId:10187] and https://www.ragic.com/tickets/ragic/1#!/1/51646
      ae.loadAllListenFields();//[BugId:10187]
      ae.setIfQueue(false);//we really need the node id, timeout is not acceptable
      ae.setSendNotification(false);//notification sent below
      ae.setCreateHistory(false);
      ScriptResponse sr = ae.save(new UserSuper(fromAddress), null);

      return sr.getRootNodeId();
   }

   private void updateFormField(NUIForm form, String fromAddress, APIEntry ae) {
      SimpleDateFormat sdf = new SimpleDateFormat("yyyy/MM/dd HH:mm:ss");
      boolean autoNoAction = getAutoNoActionByFromAddress(fromAddress);

      CellInfo lastUpdateDateField = form.getFieldByAttribute("email_updateDate", null);
      CellInfo lastUpdateEmailField = form.getFieldByAttribute("email_updateEmail", null);
      CellInfo needActionField = form.getFieldByAttribute("email_needAction", null);
      if (lastUpdateDateField != null)
         ae.setFieldValue(lastUpdateDateField.getDomainId(), sdf.format(new Date()));//last update
      if (lastUpdateEmailField != null)
         ae.setFieldValue(lastUpdateEmailField.getDomainId(), fromAddress);//last update user
      if (needActionField != null)
         ae.setFieldValue(needActionField.getDomainId(), autoNoAction ? "N" : "Y");//need action = y unless autoNoAction
      //if(debugField!=null) ae.setFieldValue(debugField.getDomainId(),ae.getFieldValue(debugField.getDomainId())+"============="+contentIdMapping.toString(2));
      ae.recalculateAllFormulas();//[BugId:10187] and https://www.ragic.com/tickets/ragic/1/60480#!/1/60480
      ae.loadAllListenFields();//[BugId:10187]
      ae.setSendNotification(false);//notification sent below
      ae.setCreateHistory(false);
      ae.save(new UserSuper(fromAddress), null);
   }

   private boolean isNotValidApname(Log log, String apname) {
      //default tickets only for main www server
      if (isTicketNotww(log, apname)) return true;

      //make sure it's intended for this server
      if (isApnameNotExistThisServer(log, apname)) {
         return true;
      }

      return false;
   }

   private boolean isApnameNotExistThisServer(Log log, String apname) {
      int maxRetryCount = 3;
      int tryCount = 1;
      boolean isNotOnThisServer = false;

      while(tryCount <= maxRetryCount){
         isNotOnThisServer = !Util.apnameExistsLocally(apname) ||
                 RedirectManager.getInstance().ifOnOtherServer(apname) ||
                 (Const.AP_DEFAULT.equalsIgnoreCase(apname) && License.isProd());

         if(isNotOnThisServer){
            tryCount ++;
         }else{
            isNotOnThisServer =  false;
            break;
         }

          try {
               Thread.sleep(100);
          }catch (InterruptedException e) {
               e.printStackTrace();
           }
      }

      if(isNotOnThisServer){
         log.info(apname + " is not on this server");
      }

      return isNotOnThisServer;
   }

   private List<String[]> getApPathSi(JSONObject messageObj, SesEmailData sesEmailData) {
      JSONArray destinations = messageObj.optJSONArray("destination");
      List<String[]> apPathSheets = new ArrayList<>();

      for (int i = 0; i < destinations.length(); i++) {
         String destination = destinations.optString(i);
         if (destination.endsWith(Const.TICKETS_DOMAIN) || destination.endsWith("@mail.ragic.com")) {
            String username = destination.substring(0, destination.indexOf("@"));
            String[] split = username.split("\\.");

            if (split.length >= 3) {
               apPathSheets.add(split);
            }
         }
      }

      //then use delivered to
      String deliveredTo = sesEmailData.getDeliveredTo();
      if(apPathSheets.size() == 0){
         if(deliveredTo.endsWith(Const.TICKETS_DOMAIN)){
            String username = deliveredTo.substring(0, deliveredTo.indexOf("@"));
            String[] split = username.split("\\.");

            if (split.length >= 3) {
               apPathSheets.add(split);
            }
         }
      }

      return apPathSheets;
   }

   private boolean isTicketNotww(Log log, String apname) {
      if("tickets".equalsIgnoreCase(apname) && !RagicConfig.getInstance().ifWWWRagicServer()){
         log.info("Tickets only for www");
         return true;
      }
      return false;
   }

   private String getFullNotification(ServletRequest request) throws IOException {
      String postBody;
      boolean test = false;
      if(test){
         postBody = request.getParameter("testRequest");
      }else{
         try (InputStreamReader isr = new InputStreamReader(request.getInputStream(), StandardCharsets.UTF_8);
              BufferedReader br = new BufferedReader(isr)) {
            int c;
            StringWriter sw = new StringWriter();
            while ((c = br.read()) != -1) {
               sw.write(c);
            }
            postBody = sw.toString();
         }
      }
      return postBody;
   }

   private boolean processDuplicate(Log log, SimpleDateFormat sdf, String downloadId) {
      if(com.ragic.s3.util.SystemCache.getInstance().get("EMAIL_MESSAGE_RCVD_"+downloadId)!=null){
         log.info("Duplicated email message notify:"+downloadId);
         return true;
      }
      else{
         com.ragic.s3.util.SystemCache.getInstance().put("EMAIL_MESSAGE_RCVD_"+downloadId,sdf.format(new Date()));
      }
      return false;
   }

   private void callAwsNotification(AwsNotificationService awsNotificationService, JSONObject notificationRequest) throws JSONException {
      awsNotificationService.sendNotification(notificationRequest);
   }


